     1→<!DOCTYPE html>
     2→<html lang="en">
     3→<head>
     4→<meta charset="UTF-8">
     5→<meta name="viewport" content="width=device-width, initial-scale=1.0, viewport-fit=cover">
     6→<title>TaskBloc</title>
     7→<script src="https://cdnjs.cloudflare.com/ajax/libs/react/18.2.0/umd/react.production.min.js"></script>
     8→<script src="https://cdnjs.cloudflare.com/ajax/libs/react-dom/18.2.0/umd/react-dom.production.min.js"></script>
     9→<script src="https://cdnjs.cloudflare.com/ajax/libs/babel-standalone/7.23.2/babel.min.js"></script>
    10→<script src="https://accounts.google.com/gsi/client" async defer></script>
    11→<link rel="apple-touch-icon" href="icon.png">
    12→<link rel="icon" type="image/png" href="data:image/png;base64,">
    13→<link rel="manifest" href="manifest.json">
    14→<meta name="apple-mobile-web-app-capable" content="yes">
    15→<meta name="apple-mobile-web-app-status-bar-style" content="default">
    16→<meta name="apple-mobile-web-app-title" content="TaskBloc">
    17→<script src="https://cdn.jsdelivr.net/npm/@supabase/supabase-js@2"></script>
    18→<link href="https://fonts.googleapis.com/css2?family=Lora:ital,wght@0,400;0,600;0,700;1,400&family=Nunito:wght@300;400;500;600;700&display=swap" rel="stylesheet">
    19→<style>
    20→*,*::before,*::after{box-sizing:border-box;margin:0;padding:0;}
    21→:root{
    22→  --bg:#faf7f2;--bg2:#f4ede3;--surface:#fffcf8;--surface2:#f7f1e8;--surface3:#ede5d8;
    23→  --border:#e0d4c3;--border2:#cfc0aa;
    24→  --accent:#c45c2a;--accent-light:#f0e8df;--accent2:#7a9e7e;--accent2-light:#e8f0e9;
    25→  --text:#3a2e24;--text2:#7a6a58;--text3:#b0a090;
    26→  --gold:#c49a3c;--gold-light:#fdf3dc;--purple:#8b6fb5;
    27→  --shadow:rgba(90,60,30,0.08);--shadow2:rgba(90,60,30,0.15);
    28→  --safe-bottom:env(safe-area-inset-bottom,0px);
    29→}
    30→html,body{height:100%;background:var(--bg);color:var(--text);font-family:'Nunito',sans-serif;overflow-x:hidden;}
    31→#root{height:100%;}
    32→::-webkit-scrollbar{width:4px;height:4px;}
    33→::-webkit-scrollbar-thumb{background:var(--border);border-radius:10px;}
    34→.app{display:flex;height:100dvh;overflow:hidden;}
    35→
    36→/* SIDEBAR */
    37→.sidebar{width:220px;min-width:220px;background:var(--surface);border-right:1px solid var(--border);display:flex;flex-direction:column;padding:24px 14px 16px;gap:2px;box-shadow:2px 0 10px var(--shadow);overflow-y:auto;flex-shrink:0;}
    38→.sidebar-logo{font-family:'Lora',serif;font-weight:700;font-size:20px;color:var(--accent);margin-bottom:4px;}
    39→.sidebar-sub{font-size:10px;color:var(--text3);margin-bottom:20px;}
    40→.sidebar-section{font-weight:700;font-size:9px;text-transform:uppercase;letter-spacing:1.3px;color:var(--text3);padding:12px 10px 5px;}
    41→.s-day{padding:9px 10px;border-radius:10px;cursor:pointer;transition:background .15s;border:1.5px solid transparent;}
    42→.s-day:hover{background:var(--surface2);}
    43→.s-day.active{background:var(--surface2);border-color:var(--border);}
    44→.s-day.today{border-color:var(--accent)!important;background:#fef4ee;}
    45→.s-day-label{font-weight:700;font-size:9px;text-transform:uppercase;letter-spacing:1px;color:var(--text3);}
    46→.s-day.today .s-day-label{color:var(--accent);}
    47→.s-day-date{font-size:12px;font-weight:600;color:var(--text);margin-top:1px;}
    48→.s-day-count{font-size:9px;color:var(--text3);margin-top:1px;}
    49→
    50→/* MAIN */
    51→.main{flex:1;overflow-y:auto;padding:28px 24px 32px;display:flex;flex-direction:column;gap:20px;}
    52→
    53→/* DAY BLOCK */
    54→.day-block{background:var(--surface);border:1px solid var(--border);border-radius:16px;padding:22px;box-shadow:0 2px 14px var(--shadow);position:relative;}
    55→.day-block::before{content:'';position:absolute;top:0;left:0;right:0;height:4px;background:linear-gradient(90deg,var(--accent),var(--gold));border-radius:16px 16px 0 0;z-index:1;}
    56→.block-header{display:flex;align-items:flex-start;justify-content:space-between;gap:10px;margin-bottom:16px;flex-wrap:wrap;}
    57→.block-title-row{display:flex;align-items:center;gap:8px;flex-wrap:wrap;}
    58→.block-title{font-family:'Lora',serif;font-weight:700;font-size:22px;color:var(--text);}
    59→.block-sub{font-family:'Nunito',sans-serif;font-weight:400;font-size:11px;color:var(--text3);margin-top:3px;font-style:italic;}
    60→
    61→/* DONE BADGES */
    62→.done-badges{display:flex;align-items:center;gap:3px;position:relative;cursor:pointer;margin-top:2px;}
    63→.done-badge{width:16px;height:16px;border-radius:50%;background:var(--accent2);display:flex;align-items:center;justify-content:center;font-size:9px;color:#fff;font-weight:700;border:1.5px solid #fff;margin-left:-4px;transition:transform .15s;}
    64→.done-badge:first-child{margin-left:0;}
    65→.done-badges:hover .done-badge{transform:scale(1.15);}
    66→.done-bubble{position:absolute;top:calc(100% + 8px);left:0;background:var(--surface);border:1.5px solid var(--border);border-radius:12px;padding:10px 12px;min-width:200px;max-width:280px;box-shadow:0 4px 20px var(--shadow2);z-index:50;animation:mIn .15s ease;}
    67→.done-bubble-title{font-size:9px;text-transform:uppercase;letter-spacing:1px;color:var(--text3);font-weight:700;margin-bottom:8px;}
    68→.done-bubble-item{display:flex;align-items:center;gap:7px;padding:5px 0;border-bottom:1px solid var(--border);font-size:12px;color:var(--text2);text-decoration:line-through;}
    69→.done-bubble-item:last-child{border-bottom:none;}
    70→.done-bubble-check{width:14px;height:14px;border-radius:50%;background:var(--accent2);flex-shrink:0;display:flex;align-items:center;justify-content:center;font-size:8px;color:#fff;}
    71→.done-bubble-close{display:block;margin-top:8px;font-size:10px;color:var(--text3);text-align:center;cursor:pointer;font-style:italic;}
    72→.done-bubble-close:hover{color:var(--accent);}
    73→
    74→/* TASK LIST - scrollable */
    75→.task-list-wrap{overflow-y:auto;max-height:calc(4 * 58px);display:flex;flex-direction:column;gap:6px;padding-right:2px;}
    76→.task-list-wrap::-webkit-scrollbar{width:3px;}
    77→.task-list-wrap::-webkit-scrollbar-thumb{background:var(--border2);border-radius:10px;}
    78→
    79→/* BUTTONS */
    80→.btn{padding:7px 15px;border-radius:20px;font-family:'Nunito',sans-serif;font-size:12px;font-weight:600;cursor:pointer;border:1.5px solid var(--border);background:var(--surface2);color:var(--text2);transition:all .15s;white-space:nowrap;}
    81→.btn:hover{background:var(--surface3);border-color:var(--border2);color:var(--text);}
    82→.btn:disabled{opacity:.5;cursor:default;}
    83→.btn.primary{background:var(--accent);color:#fff;border-color:var(--accent);}
    84→.btn.primary:hover{background:#b05025;}
    85→.btn.gold{background:var(--gold-light);border-color:#e0c070;color:var(--gold);}
    86→.btn.gold:hover{background:#fcefd0;border-color:var(--gold);}
    87→.btn.danger{background:#fde8e8;border-color:#f0b8b8;color:#c0392b;}
    88→.btn.danger:hover{background:#fbd0d0;}
    89→.btn.sm{padding:5px 11px;font-size:11px;}
    90→.btn.purple{background:var(--purple-light,#f0ebf8);border-color:#c5aee8;color:var(--purple);}
    91→.btn.purple:hover{background:#e8e0f5;}
    92→
    93→.add-row{display:flex;gap:8px;margin-bottom:14px;}
    94→.add-input{flex:1;background:var(--surface2);border:1.5px solid var(--border);border-radius:20px;padding:9px 15px;font-family:'Nunito',sans-serif;font-size:13px;color:var(--text);outline:none;transition:border-color .15s;min-width:0;}
    95→.add-input::placeholder{color:var(--text3);}
    96→.add-input:focus{border-color:var(--accent);box-shadow:0 0 0 3px rgba(196,92,42,.1);}
    97→
    98→/* TASK ITEMS */
    99→.task-item{background:var(--surface2);border:1.5px solid var(--border);border-radius:12px;padding:11px 13px;display:flex;align-items:center;gap:9px;cursor:grab;transition:all .15s;position:relative;user-select:none;box-shadow:0 1px 3px var(--shadow);flex-shrink:0;}
   100→.task-item:hover{border-color:var(--border2);background:var(--surface);box-shadow:0 2px 8px var(--shadow2);transform:translateY(-1px);}
   101→.task-item.dragging{opacity:.4;cursor:grabbing;transform:none;}
   102→.task-item.drag-over{border-color:var(--accent);border-style:dashed;background:#fef4ee;}
   103→.drag-handle{color:var(--text3);font-size:13px;opacity:.4;flex-shrink:0;}
   104→.task-item:hover .drag-handle{opacity:1;}
   105→.task-check{width:18px;height:18px;border-radius:50%;border:2px solid var(--border2);flex-shrink:0;cursor:pointer;display:flex;align-items:center;justify-content:center;transition:all .15s;}
   106→.task-check:hover{border-color:var(--accent2);background:var(--accent2-light);}
   107→.task-check.on{background:var(--accent2);border-color:var(--accent2);}
   108→.task-check.on::after{content:'✓';font-size:10px;color:#fff;font-weight:700;}
   109→.task-body{flex:1;min-width:0;}
   110→.task-name{font-size:13px;font-weight:600;color:var(--text);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;}
   111→.task-status{font-size:10px;color:var(--accent);margin-top:2px;font-style:italic;font-weight:500;}
   112→.task-meta{display:flex;align-items:center;gap:5px;flex-shrink:0;}
   113→.attach-badge{font-size:10px;color:var(--text3);}
   114→.open-btn{background:none;border:none;color:var(--text3);cursor:pointer;font-size:14px;padding:3px 5px;border-radius:6px;transition:all .12s;flex-shrink:0;}
   115→.open-btn:hover{color:var(--accent);background:var(--accent-light);}
   116→
   117→/* complete animation */
   118→@keyframes completeSlide{from{opacity:1;transform:translateX(0);}to{opacity:0;transform:translateX(30px);}}
   119→.task-item.completing{animation:completeSlide .3s ease forwards;}
   120→
   121→.drop-zone-hint{border:2px dashed var(--border);border-radius:10px;padding:9px;text-align:center;font-size:11px;color:var(--text3);margin-top:10px;transition:all .15s;font-style:italic;flex-shrink:0;}
   122→.drop-zone-hint.active{border-color:var(--accent);color:var(--accent);background:#fef4ee;}
   123→
   124→/* WEEK STRIP */
   125→.strip-label{font-weight:700;font-size:9px;text-transform:uppercase;letter-spacing:1.5px;color:var(--text3);}
   126→.week-row{display:flex;gap:8px;overflow-x:auto;padding-bottom:4px;}
   127→.week-card{min-width:140px;background:var(--surface);border:1.5px solid var(--border);border-radius:13px;padding:12px;flex-shrink:0;cursor:pointer;transition:all .15s;box-shadow:0 1px 5px var(--shadow);}
   128→.week-card:hover{border-color:var(--border2);box-shadow:0 3px 10px var(--shadow2);transform:translateY(-1px);}
   129→.week-card.drop-target{border-color:var(--accent)!important;background:#fef4ee;}
   130→.week-card.is-today{border-color:var(--accent);background:#fef4ee;}
   131→.week-card-header{display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:8px;}
   132→.week-day-name{font-weight:700;font-size:10px;text-transform:uppercase;letter-spacing:.7px;color:var(--text3);}
   133→.week-day-month{font-size:8px;color:var(--text3);margin-top:1px;}
   134→.week-day-num{font-family:'Lora',serif;font-weight:700;font-size:20px;color:var(--text);line-height:1;}
   135→.week-pill{background:var(--surface2);border-radius:5px;padding:4px 7px;font-size:10px;color:var(--text2);margin-bottom:3px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;display:flex;align-items:center;gap:5px;border:1px solid var(--border);}
   136→.week-pill.done{text-decoration:line-through;color:var(--text3);opacity:.5;}
   137→.week-pill-dot{width:4px;height:4px;border-radius:50%;background:var(--accent);flex-shrink:0;}
   138→.week-pill.done .week-pill-dot{background:var(--text3);}
   139→.week-empty{font-size:10px;color:var(--text3);font-style:italic;}
   140→
   141→/* LOOKING FORWARD */
   142→.lf-block{background:var(--surface);border:1.5px solid var(--border);border-radius:16px;padding:20px;box-shadow:0 2px 10px var(--shadow);position:relative;}
   143→.lf-block::before{content:'';position:absolute;top:0;left:0;right:0;height:4px;background:linear-gradient(90deg,var(--purple),#b8a0d8);border-radius:16px 16px 0 0;}
   144→.lf-block.drop-active{border-color:var(--purple);background:#f8f4fc;}
   145→.lf-title{font-family:'Lora',serif;font-weight:600;font-size:17px;color:var(--text);margin-bottom:4px;}
   146→.lf-sub{font-size:11px;color:var(--text3);font-style:italic;margin-bottom:12px;}
   147→.lf-list{overflow-y:auto;max-height:280px;display:flex;flex-direction:column;gap:6px;margin-bottom:10px;}
   148→.lf-list::-webkit-scrollbar{width:3px;}
   149→.lf-list::-webkit-scrollbar-thumb{background:var(--border2);border-radius:10px;}
   150→.lf-item{background:var(--surface2);border:1.5px solid var(--border);border-radius:10px;padding:9px 12px;display:flex;align-items:center;gap:9px;box-shadow:0 1px 3px var(--shadow);transition:all .15s;flex-shrink:0;}
   151→.lf-item:hover{border-color:var(--border2);background:var(--surface);}
   152→.lf-dot{width:7px;height:7px;border-radius:50%;background:var(--purple);flex-shrink:0;opacity:.6;}
   153→.lf-name{flex:1;font-size:13px;font-weight:600;color:var(--text);min-width:0;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;}
   154→.lf-remove{background:none;border:none;color:var(--text3);cursor:pointer;font-size:13px;padding:2px 5px;border-radius:5px;transition:all .12s;}
   155→.lf-remove:hover{color:var(--accent);background:var(--accent-light);}
   156→.lf-drop-hint{border:2px dashed var(--border);border-radius:10px;padding:14px;text-align:center;font-size:12px;color:var(--text3);font-style:italic;transition:all .15s;}
   157→.lf-block.drop-active .lf-drop-hint{border-color:var(--purple);color:var(--purple);background:rgba(139,111,181,.05);}
   158→.lf-add-row{display:flex;gap:8px;margin-bottom:10px;}
   159→.lf-add-input{flex:1;background:var(--surface2);border:1.5px solid var(--border);border-radius:20px;padding:8px 14px;font-family:'Nunito',sans-serif;font-size:13px;color:var(--text);outline:none;transition:border-color .15s;min-width:0;}
   160→.lf-add-input::placeholder{color:var(--text3);}
   161→.lf-add-input:focus{border-color:var(--purple);box-shadow:0 0 0 3px rgba(139,111,181,.1);}
   162→
   163→/* MODALS */
   164→.overlay{position:fixed;inset:0;background:rgba(60,40,20,.45);display:flex;align-items:center;justify-content:center;z-index:200;backdrop-filter:blur(5px);padding:16px;}
   165→.modal{background:var(--surface);border:1.5px solid var(--border);border-radius:18px;padding:26px;width:100%;max-width:500px;max-height:90dvh;overflow-y:auto;display:flex;flex-direction:column;gap:16px;animation:mIn .18s ease;box-shadow:0 8px 40px rgba(60,40,20,.18);}
   166→@keyframes mIn{from{opacity:0;transform:scale(.95) translateY(8px);}to{opacity:1;transform:scale(1) translateY(0);}}
   167→.modal-header{display:flex;justify-content:space-between;align-items:flex-start;}
   168→.modal-title{font-family:'Lora',serif;font-weight:600;font-size:18px;color:var(--text);flex:1;margin-right:10px;line-height:1.3;}
   169→.modal-close{background:var(--surface2);border:1px solid var(--border);color:var(--text3);font-size:13px;cursor:pointer;padding:4px 8px;border-radius:7px;transition:all .12s;}
   170→.modal-close:hover{background:var(--surface3);color:var(--text);}
   171→.field label{display:block;font-size:9px;text-transform:uppercase;letter-spacing:1px;color:var(--text3);margin-bottom:5px;font-weight:700;}
   172→.m-input{width:100%;background:var(--surface2);border:1.5px solid var(--border);border-radius:10px;padding:9px 13px;font-family:'Nunito',sans-serif;font-size:13px;color:var(--text);outline:none;transition:border-color .15s;}
   173→.m-input:focus{border-color:var(--accent);box-shadow:0 0 0 3px rgba(196,92,42,.1);}
   174→.m-input::placeholder{color:var(--text3);}
   175→.m-textarea{width:100%;background:var(--surface2);border:1.5px solid var(--border);border-radius:10px;padding:9px 13px;font-family:'Nunito',sans-serif;font-size:13px;color:var(--text);outline:none;resize:vertical;min-height:80px;transition:border-color .15s;line-height:1.6;}
   176→.m-textarea:focus{border-color:var(--accent);box-shadow:0 0 0 3px rgba(196,92,42,.1);}
   177→.m-textarea::placeholder{color:var(--text3);}
   178→.divider{height:1px;background:var(--border);}
   179→.modal-footer{display:flex;justify-content:space-between;align-items:center;padding-top:4px;border-top:1px solid var(--border);}
   180→.footer-right{display:flex;gap:8px;}
   181→.trash-btn{background:none;border:1.5px solid #f0b8b8;border-radius:20px;color:#c0392b;cursor:pointer;padding:6px 12px;display:flex;align-items:center;gap:5px;font-family:'Nunito',sans-serif;font-size:12px;font-weight:600;transition:all .15s;}
   182→.trash-btn:hover{background:#fde8e8;}
   183→
   184→/* ATTACHMENTS */
   185→.file-drop{border:2px dashed var(--border2);border-radius:11px;padding:18px;text-align:center;cursor:pointer;transition:all .2s;background:var(--surface2);position:relative;}
   186→.file-drop:hover,.file-drop.over{border-color:var(--accent);background:#fef4ee;}
   187→.file-drop input{position:absolute;inset:0;opacity:0;cursor:pointer;width:100%;height:100%;}
   188→.file-drop-icon{font-size:20px;margin-bottom:4px;}
   189→.file-drop-label{font-size:12px;font-weight:600;color:var(--text2);}
   190→.file-drop-sub{font-size:10px;color:var(--text3);margin-top:2px;font-style:italic;}
   191→.link-row{display:flex;gap:7px;}
   192→.attach-list{display:flex;flex-direction:column;gap:5px;}
   193→.attach-item{display:flex;align-items:center;gap:9px;background:var(--surface2);border:1.5px solid var(--border);border-radius:9px;padding:8px 11px;transition:all .12s;}
   194→.attach-item:hover{border-color:var(--border2);background:var(--surface);}
   195→.a-icon{width:30px;height:30px;border-radius:7px;display:flex;align-items:center;justify-content:center;font-size:14px;flex-shrink:0;}
   196→.a-icon.pdf{background:#fde8e8;}.a-icon.img{background:#e8f0e9;}.a-icon.doc{background:#e8eef8;}.a-icon.lnk{background:var(--gold-light);}.a-icon.def{background:var(--surface3);}
   197→.a-info{flex:1;min-width:0;}
   198→.a-name{font-size:11px;font-weight:600;color:var(--text);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;}
   199→.a-meta{font-size:10px;color:var(--text3);font-style:italic;}
   200→.a-remove{background:none;border:none;color:var(--text3);cursor:pointer;font-size:13px;padding:2px 5px;border-radius:5px;transition:all .12s;}

