   200→.a-remove{background:none;border:none;color:var(--text3);cursor:pointer;font-size:13px;padding:2px 5px;border-radius:5px;transition:all .12s;}
   201→.a-remove:hover{color:var(--accent);background:var(--accent-light);}
   202→
   203→/* SYNC */
   204→.sync-bar{display:flex;align-items:center;gap:6px;font-size:10px;color:var(--text3);padding:4px 0;}
   205→.sync-dot{width:6px;height:6px;border-radius:50%;background:var(--text3);flex-shrink:0;}
   206→.sync-dot.ok{background:var(--accent2);}
   207→.sync-dot.err{background:#c0392b;}
   208→.sync-dot.syncing{background:var(--gold);animation:pulse 1s infinite;}
   209→@keyframes pulse{0%,100%{opacity:1;}50%{opacity:.3;}}
   210→
   211→/* MOBILE */
   212→.mob-nav{display:none;}
   213→@media(max-width:680px){
   214→  .sidebar{display:none;}
   215→  .main{padding:14px 12px 80px;}
   216→  .day-block{padding:16px 14px;border-radius:14px;}
   217→  .block-title{font-size:19px;}
   218→  .block-sub{font-size:10px;}
   219→  .add-input{font-size:14px;padding:10px 14px;}
   220→  .task-item{padding:12px 11px;}
   221→  .task-name{font-size:14px;}
   222→  .week-card{min-width:120px;padding:10px;}
   223→  .week-day-num{font-size:17px;}
